const crypto = require('crypto');
const https = require('https');

const APP_KEY    = 'db98a65eba39bf6886faf56e9249589e';
const APP_SECRET = '3896fff8060522f365d380dc03db8a6d57c5fad6';
const ACCESS_TOKEN = $input.first().json.access_token;

if (!ACCESS_TOKEN) throw new Error('No access_token in config.temu_credentials');

function buildSign(params) {
  const keys = Object.keys(params).sort();
  let s = APP_SECRET;
  for (const k of keys) s += k + String(params[k]);
  s += APP_SECRET;
  return crypto.createHash('md5').update(s).digest('hex').toUpperCase();
}

async function temuPost(type, reqBody = {}) {
  const timestamp = String(Math.floor(Date.now() / 1000));
  const sysParams = { type, app_key: APP_KEY, access_token: ACCESS_TOKEN, timestamp, data_type: 'JSON' };
  const sign = buildSign(sysParams);
  const qs = Object.entries({ ...sysParams, sign }).map(([k,v]) => `${k}=${encodeURIComponent(v)}`).join('&');
  const body = JSON.stringify(Object.keys(reqBody).length ? { request: reqBody } : {});

  return new Promise((resolve, reject) => {
    const opts = {
      hostname: 'openapi-b-eu.temu.com',
      path: `/openapi/router?${qs}`,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) }
    };
    const req = https.request(opts, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({ raw: d }); } });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

// Extrage categorii frunza recursiv din arborele returnat de Temu
function extractLeaves(list, out = []) {
  for (const cat of (list || [])) {
    const children = cat.children || cat.childList || cat.child_list || [];
    const isLeaf = cat.leaf === true || cat.leaf === 1 || !children.length;
    if (isLeaf) {
      out.push({
        category_id: String(cat.catId || cat.cat_id || cat.id),
        category_name: String(cat.catName || cat.cat_name || cat.name)
      });
    } else {
      extractLeaves(children, out);
    }
  }
  return out;
}

const resp = await temuPost('bg.local.goods.cats.get');

if (!resp.success) {
  throw new Error('bg.local.goods.cats.get failed: ' + JSON.stringify(resp));
}

// Campul cu lista difera in functie de versiunea API
const catList =
  resp.result?.catList ||
  resp.result?.cats ||
  resp.result?.categoryList ||
  resp.result?.cat_list ||
  [];

if (!catList.length) {
  throw new Error('Empty category list from Temu. Full response: ' + JSON.stringify(resp.result));
}

const leaves = extractLeaves(catList);

if (!leaves.length) {
  throw new Error('No leaf categories found. catList sample: ' + JSON.stringify(catList.slice(0, 2)));
}

// Returnam o singura inregistrare cu array-ul JSON pentru upsert bulk eficient
return [{ json: { categories: JSON.stringify(leaves), count: leaves.length } }];
